import { ImageResponse } from 'next/og'
import { NextRequest } from 'next/server'

export const runtime = 'edge'

const LOGO = "data:image/png;base64,"

export async function GET(request: NextRequest) {
  const { searchParams } = new URL(request.url)
  const dogName  = searchParams.get('dog') || 'Your Dog'
  const sessions = searchParams.get('sessions') || '0'
  const miles    = searchParams.get('miles') || '0.00'
  const calories = searchParams.get('calories') || '0'
  const peak     = searchParams.get('peak') || null
  const city     = searchParams.get('city') || ''
  const photoUrl = searchParams.get('photo') || ''

  return new ImageResponse(
    (
      <div style={{
        width: '1200px', height: '630px',
        background: 'white',
        display: 'flex', flexDirection: 'row',
        fontFamily: 'Arial, sans-serif',
        position: 'relative', overflow: 'hidden',
      }}>

        {/* Orange left accent bar */}
        <div style={{ position: 'absolute', left: 0, top: 0, width: '8px', height: '630px', background: 'linear-gradient(180deg, #f88124, #f9a04e)', display: 'flex' }} />

        {/* LEFT PANEL */}
        <div style={{
          width: '400px',
          background: 'linear-gradient(160deg, #001840 0%, #0d2d5e 100%)',
          display: 'flex', flexDirection: 'column',
          alignItems: 'center', justifyContent: 'center',
          paddingLeft: '8px', position: 'relative', overflow: 'hidden',
        }}>
          <div style={{ position: 'absolute', bottom: -60, right: -60, width: '200px', height: '200px', borderRadius: '50%', background: 'rgba(248,129,36,0.12)', display: 'flex' }} />

          {/* Logo */}
          <img src={LOGO} style={{ height: '48px', width: 'auto', marginBottom: '28px', objectFit: 'contain' }} />

          {/* Dog photo */}
          <div style={{
            width: '180px', height: '180px', borderRadius: '24px',
            border: '3px solid rgba(248,129,36,0.7)',
            overflow: 'hidden', display: 'flex',
            boxShadow: '0 16px 48px rgba(0,0,0,0.5)',
          }}>
            {photoUrl ? (
              <img src={photoUrl} style={{ width: '180px', height: '180px', objectFit: 'cover' }} />
            ) : (
              <div style={{ width: '180px', height: '180px', background: 'rgba(255,255,255,0.08)', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: '64px' }}>🐾</div>
            )}
          </div>

          {/* Dog name */}
          <div style={{ marginTop: '20px', fontSize: '38px', fontWeight: '900', color: 'white', display: 'flex', lineHeight: 1.1, textAlign: 'center', paddingLeft: '16px', paddingRight: '16px' }}>{dogName}</div>

          {/* City */}
          {city ? (
            <div style={{ marginTop: '8px', fontSize: '15px', color: 'rgba(255,255,255,0.5)', display: 'flex', alignItems: 'center', gap: '5px' }}>📍 {city}</div>
          ) : null}
        </div>

        {/* RIGHT PANEL */}
        <div style={{
          flex: 1, display: 'flex', flexDirection: 'column',
          justifyContent: 'center', padding: '52px 52px 44px 52px',
          background: 'white',
        }}>
          {/* Eyebrow + headline */}
          <div style={{ marginBottom: '28px', display: 'flex', flexDirection: 'column', gap: '6px' }}>
            <div style={{ fontSize: '12px', fontWeight: '800', color: '#f88124', letterSpacing: '3px', display: 'flex' }}>FITNESS SUMMARY</div>
            <div style={{ fontSize: '34px', fontWeight: '900', color: '#001840', display: 'flex', lineHeight: 1.1 }}>{dogName}&apos;s Stats 🐾</div>
          </div>

          {/* Row 1 */}
          <div style={{ display: 'flex', gap: '16px', marginBottom: '16px' }}>
            <div style={{ flex: 1, background: '#f8f9fc', borderRadius: '16px', padding: '20px 24px', border: '1.5px solid #eef0f5', display: 'flex', flexDirection: 'column', gap: '8px' }}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#f88124" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M8 2v4M16 2v4M3 10h18M5 4h14a2 2 0 0 1 2 2v14a2 2 0 0 1-2 2H5a2 2 0 0 1-2-2V6a2 2 0 0 1 2-2z" /></svg>
              <div style={{ fontSize: '34px', fontWeight: '900', color: '#001840', display: 'flex', lineHeight: 1 }}>{sessions}</div>
              <div style={{ fontSize: '11px', fontWeight: '800', color: '#aaa', letterSpacing: '1.5px', display: 'flex' }}>SESSIONS</div>
            </div>
            <div style={{ flex: 1, background: '#f8f9fc', borderRadius: '16px', padding: '20px 24px', border: '1.5px solid #eef0f5', display: 'flex', flexDirection: 'column', gap: '8px' }}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#f88124" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M3 11l19-9-9 19-2-8-8-2z" /></svg>
              <div style={{ fontSize: '34px', fontWeight: '900', color: '#001840', display: 'flex', lineHeight: 1 }}>{miles} mi</div>
              <div style={{ fontSize: '11px', fontWeight: '800', color: '#aaa', letterSpacing: '1.5px', display: 'flex' }}>TOTAL MILES</div>
            </div>
          </div>

          {/* Row 2 */}
          <div style={{ display: 'flex', gap: '16px' }}>
            <div style={{ flex: 1, background: '#f8f9fc', borderRadius: '16px', padding: '20px 24px', border: '1.5px solid #eef0f5', display: 'flex', flexDirection: 'column', gap: '8px' }}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#f88124" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M8.5 14.5A2.5 2.5 0 0 0 11 12c0-1.38-.5-2-1-3-1.072-2.143-.224-4.054 2-6 .5 2.5 2 4.9 4 6.5 2 1.6 3 3.5 3 5.5a7 7 0 1 1-14 0c0-1.153.433-2.294 1-3a2.5 2.5 0 0 0 2.5 2.5z" /></svg>
              <div style={{ fontSize: '34px', fontWeight: '900', color: '#001840', display: 'flex', lineHeight: 1 }}>{calories} cal</div>
              <div style={{ fontSize: '11px', fontWeight: '800', color: '#aaa', letterSpacing: '1.5px', display: 'flex' }}>CALORIES</div>
            </div>
            <div style={{ flex: 1, background: '#f8f9fc', borderRadius: '16px', padding: '20px 24px', border: '1.5px solid #eef0f5', display: 'flex', flexDirection: 'column', gap: '8px' }}>
              <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#f88124" strokeWidth="2.5" strokeLinecap="round" strokeLinejoin="round"><path d="M13 2L3 14h9l-1 8 10-12h-9l1-8z" /></svg>
              <div style={{ fontSize: '34px', fontWeight: '900', color: '#001840', display: 'flex', lineHeight: 1 }}>{peak ? `${peak} mph` : '—'}</div>
              <div style={{ fontSize: '11px', fontWeight: '800', color: '#aaa', letterSpacing: '1.5px', display: 'flex' }}>PEAK SPEED</div>
            </div>
          </div>

          {/* Footer */}
          <div style={{ marginTop: '20px', fontSize: '13px', color: '#ccc', display: 'flex' }}>thecaninegym.com</div>
        </div>

      </div>
    ),
    { width: 1200, height: 630 }
  )
}